import type { DMMF } from '@prisma/dmmf'

/**
 * Maps a DMMF field to its TypeScript type string, respecting list and optional
 * modifiers as well as scalar, enum, and relation kinds.
 */
export function mapFieldTypeToTs(field: DMMF.Field): string {
  const base = field.kind === 'object' || field.kind === 'enum' ? field.type : mapScalarToTs(field.type)
  return field.isList ? `${base}[]` : base
}

function mapScalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Bytes':
      return 'Uint8Array'
    case 'Json':
      return 'unknown'
    default:
      return 'unknown'
  }
}

/**
 * Converts a PascalCase model name to its kebab-case REST resource path segment.
 *
 * @example `BlogPost` → `blog-post`
 */
export function toKebabCase(name: string): string {
  return name.replace(/([A-Z])/g, (match, letter, offset: number) => (offset > 0 ? '-' : '') + letter.toLowerCase())
}

/**
 * Converts a PascalCase model name to its camelCase accessor property name.
 *
 * @example `BlogPost` → `blogPost`
 */
export function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Renders a TypeScript interface for the model's scalar and enum fields.
 * Relation fields are intentionally excluded because they are represented
 * through separate typed CRUD accessors.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = f.isRequired ? '' : '?'
      return `  ${f.name}${optional}: ${mapFieldTypeToTs(f)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Renders a `{Model}CreateInput` interface for use in POST request bodies.
 * Auto-generated and read-only fields are excluded; fields with defaults are
 * marked optional.
 */
export function renderCreateInputInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
    .map((f) => {
      // Fields with server-side defaults (autoincrement, uuid, now, …) are optional on create.
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${mapFieldTypeToTs(f)}`
    })
